public class CustomEnchantment extends Enchantment {
    public CustomEnchantment() {
        super(Rarity.RARE, EnchantmentTarget.WEAPON, new EquipmentSlot[]{EquipmentSlot.MAINHAND});
    }
    @Override
    public int getMinLevel() { return 1; }
    @Override
    public int getMaxLevel() { return 3; }
}

public class ModEnchantments {
    public static final Enchantment CUSTOM_ENCHANTMENT = new CustomEnchantment();
    public static void register() {
        Registry.register(Registries.ENCHANTMENT, new Identifier("modid", "custom_enchantment"), CUSTOM_ENCHANTMENT);
    }
}

@Override
public void onTargetDamaged(LivingEntity user, Entity target, int level) {
    if (target instanceof LivingEntity living) {
        living.damage(user.getDamageSources().magic(), level * 2);
    }
}

@Override
public void onUserDamaged(LivingEntity user, Entity attacker, int level) {
    if (attacker instanceof LivingEntity living) {
        living.addStatusEffect(new StatusEffectInstance(StatusEffects.SLOWNESS, 100, level - 1));
    }
}

@Override
public boolean canAccept(Enchantment other) {
    if (other == Enchantments.SHARPNESS) {
        return false;
    }
    return super.canAccept(other);
}

@Override
public int getMinPower(int level) { return 10 + (level - 1) * 8; }
@Override
public int getMaxPower(int level) { return getMinPower(level) + 20; }

@Override
public boolean isTreasure() { return true; }
@Override
public boolean isAvailableForEnchantedBookOffer() { return true; }
@Override
public boolean isAvailableForRandomSelection() { return false; }
